	//repeat square method y = x^n mod quotient 

	ll rsm(ll x, ll n, ll quotient) {

		ll y = 1;

		while (n > 0) {

			if ((n & 1) == 1) {

				y *= x;

				y %= quotient;

			}

			x *= x;

			x %= quotient;

			n >>= 1;

		}

		return y;

	}



