	ll nCk(ll n, ll k, ll quotient) {

		if (n < k) return 0;

		if (k == 0) return 1;

		ll nCk = (factorial[n] % quotient);

		nCk *= rsm(factorial[k], quotient - 2, quotient);

		nCk %= quotient;

		nCk *= rsm(factorial[n - k], quotient - 2, quotient);

		return (nCk % quotient);

	}

};



