			}

		}

		return;

	}



	//get least common ancestor

	int get(int a, int b) {

		if (depth[a] > depth[b]) swap(a, b);

		REP(k, MAXLOG2 - 1) if (((depth[b] - depth[a]) >> k) & 1) b = parent[b][k];

		if (a == b) return a;

		REREP(k, MAXLOG2) {

			if (parent[a][k] != parent[b][k]) {

				a = parent[a][k];

				b = parent[b][k];

			}

		}

		return parent[a][0];

	}

};



