	long long n, a, b, k;

	scanf("%lld%lld%lld%lld", &n, &a, &b, &k);

	fac[0] = 1;

	for (int i = 1; i <= n; ++i) {

		fac[i] = fac[i - 1] * i % MOD;

	}

	ifac[n] = inverse(fac[n]);

	for (int i = n; i >= 1; --i) {

		ifac[i - 1] = ifac[i] * i % MOD;

	}

	long long ans = 0;

