		if ((k - i * a) % b == 0 && (k - i * a) / b <= n) {

			ans = (ans + C(n, i) * C(n, (k - i * a) / b) % MOD) % MOD;

		}

	}

	printf("%lld\n", ans);

	return 0;

}

